   231→    public void run() {
   232→        try {
   233→            printJson(new StartupComplete());
   234→            consumer.subscribe(Collections.singletonList(topic), this);
   235→
   236→            while (!isFinished()) {
   237→                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(Long.MAX_VALUE));
   238→                Map<TopicPartition, OffsetAndMetadata> offsets = onRecordsReceived(records);
   239→
   240→                if (!useAutoCommit) {
   241→                    if (useAsyncCommit)
   242→                        consumer.commitAsync(offsets, this);
   243→                    else
   244→                        commitSync(offsets);
   245→                }
   246→            }
   247→        } catch (WakeupException e) {
