   152→
   153→            if (hasMessageLimit() && consumedMessages + partitionRecords.size() > maxMessages)
   154→                partitionRecords = partitionRecords.subList(0, maxMessages - consumedMessages);
   155→
   156→            if (partitionRecords.isEmpty())
   157→                continue;
   158→
   159→            long minOffset = partitionRecords.get(0).offset();
   160→            long maxOffset = partitionRecords.get(partitionRecords.size() - 1).offset();
   161→
   162→            offsets.put(tp, new OffsetAndMetadata(maxOffset + 1));
   163→            summaries.add(new RecordSetSummary(tp.topic(), tp.partition(),
   164→                    partitionRecords.size(), minOffset, maxOffset));
   165→
   166→            if (verbose) {
   167→                for (ConsumerRecord<String, String> record : partitionRecords) {
   168→                    printJson(new RecordData(record));
   169→                }
   170→            }
   171→
   172→            consumedMessages += partitionRecords.size();
   173→            if (isFinished())
   174→                break;
   175→        }
   176→
   177→        printJson(new RecordsConsumed(records.count(), summaries));
   178→        return offsets;
   179→    }
   180→
   181→    @Override
   182→    public void onComplete(Map<TopicPartition, OffsetAndMetadata> offsets, Exception exception) {
   183→        List<CommitData> committedOffsets = new ArrayList<>();
   184→        for (Map.Entry<TopicPartition, OffsetAndMetadata> offsetEntry : offsets.entrySet()) {
   185→            TopicPartition tp = offsetEntry.getKey();
   186→            committedOffsets.add(new CommitData(tp.topic(), tp.partition(), offsetEntry.getValue().offset()));
   187→        }
   188→
   189→        boolean success = true;
   190→        String error = null;
   191→        if (exception != null) {
   192→            success = false;
   193→            error = exception.getMessage();
   194→        }
   195→        printJson(new OffsetsCommitted(committedOffsets, error, success));
   196→    }
