   208→    private void printJson(Object data) {
   209→        try {
   210→            out.println(mapper.writeValueAsString(data));
   211→        } catch (JsonProcessingException e) {
   212→            out.println("Bad data can't be written as json: " + e.getMessage());
   213→        }
   214→    }
