   216→    public void commitSync(Map<TopicPartition, OffsetAndMetadata> offsets) {
   217→        try {
   218→            consumer.commitSync(offsets);
   219→            onComplete(offsets, null);
   220→        } catch (WakeupException e) {
   221→            // we only call wakeup() once to close the consumer, so this recursion should be safe
   222→            commitSync(offsets);
   223→            throw e;
   224→        } catch (FencedInstanceIdException e) {
   225→            throw e;
   226→        } catch (Exception e) {
   227→            onComplete(offsets, e);
   228→        }
   229→    }
