   231→    public void run() {
   232→        try {
   233→            printJson(new StartupComplete());
   234→            consumer.subscribe(Collections.singletonList(topic), this);
   235→
   236→            while (!isFinished()) {
   237→                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(Long.MAX_VALUE));
   238→                Map<TopicPartition, OffsetAndMetadata> offsets = onRecordsReceived(records);
   239→
   240→                if (!useAutoCommit) {
   241→                    if (useAsyncCommit)
   242→                        consumer.commitAsync(offsets, this);
   243→                    else
   244→                        commitSync(offsets);
   245→                }
   246→            }
   247→        } catch (WakeupException e) {
   248→            // ignore, we are closing
   249→            log.trace("Caught WakeupException because consumer is shutdown, ignore and terminate.", e);
   250→        } catch (Throwable t) {
   251→            // Log the error so it goes to the service log and not stdout
   252→            log.error("Error during processing, terminating consumer process: ", t);
   253→        } finally {
   254→            consumer.close();
   255→            printJson(new ShutdownComplete());
   256→            shutdownLatch.countDown();
   257→        }
   258→    }
   259→
   260→    public void close() {
   261→        boolean interrupted = false;
   262→        try {
   263→            consumer.wakeup();
   264→            while (true) {
   265→                try {
   266→                    shutdownLatch.await();
   267→                    return;
   268→                } catch (InterruptedException e) {
   269→                    interrupted = true;
   270→                }
   271→            }
   272→        } finally {
   273→            if (interrupted)
   274→                Thread.currentThread().interrupt();
   275→        }
   276→    }
