    40→import java.util.HashMap;
    41→import java.util.Map;
    42→import java.util.Optional;
    43→import java.util.concurrent.CountDownLatch;
    44→
    45→import static java.time.Duration.ofMillis;
    46→import static java.util.Collections.emptyList;
    47→import static java.util.Collections.singleton;
    48→
    49→/**
    50→ * This class implements a read-process-write application.
    51→ */
    52→public class ExactlyOnceMessageProcessor extends Thread implements ConsumerRebalanceListener, AutoCloseable {
    53→    private static final int MAX_RETRIES = 5;
    54→    
    55→    private final String bootstrapServers;
    56→    private final String inputTopic;
    57→    private final String outputTopic;
    58→    private final String groupInstanceId;
    59→    private final CountDownLatch latch;
    60→    private final String transactionalId;
    61→    private volatile boolean closed;
    62→
    63→    private final KafkaProducer<Integer, String> producer;
    64→    private final KafkaConsumer<Integer, String> consumer;
    65→
    66→    public ExactlyOnceMessageProcessor(String threadName,
    67→                                       String bootstrapServers,
    68→                                       String inputTopic,
    69→                                       String outputTopic,
    70→                                       CountDownLatch latch) {
    71→        super(threadName);
    72→        this.bootstrapServers = bootstrapServers;
    73→        this.inputTopic = inputTopic;
    74→        this.outputTopic = outputTopic;
    75→        this.transactionalId = "tid-" + threadName;
    76→        // It is recommended to have a relatively short txn timeout in order to clear pending offsets faster.
    77→        int transactionTimeoutMs = 10_000;
    78→        // A unique transactional.id must be provided in order to properly use EOS.
    79→        producer = new Producer(
    80→                "processor-producer",
    81→                KafkaProperties.BOOTSTRAP_SERVERS,
    82→                outputTopic,
    83→                true,
    84→                transactionalId,
    85→                true,
    86→                -1,
    87→                transactionTimeoutMs,
    88→                null)
    89→                .createKafkaProducer();
