    91→        // Consumer could optionally configure groupInstanceId to avoid unnecessary rebalances.
    92→        this.groupInstanceId = "giid-" + threadName;
    93→        boolean readCommitted = true;
    94→        consumer = new Consumer(
    95→                "processor-consumer",
    96→                KafkaProperties.BOOTSTRAP_SERVERS,
    97→                inputTopic,
    98→                "processor-group",
    99→                Optional.of(groupInstanceId),
   100→                readCommitted,
   101→                -1,
   102→                null)
   103→                .createKafkaConsumer();
   104→        this.latch = latch;
   105→    }
   106→
   107→    @Override
   108→    public void run() {
   109→        int retries = 0;
   110→        int processedRecords = 0;
   111→        long remainingRecords = Long.MAX_VALUE;
   112→
   113→        // it is recommended to have a relatively short txn timeout in order to clear pending offsets faster
   114→        int transactionTimeoutMs = 10_000;
   115→        // consumer must be in read_committed mode, which means it won't be able to read uncommitted data
   116→        boolean readCommitted = true;
   117→
   118→        try (KafkaProducer<Integer, String> producer = new Producer("processor-producer", bootstrapServers, outputTopic,
   119→                true, transactionalId, true, -1, transactionTimeoutMs, null).createKafkaProducer();
   120→             KafkaConsumer<Integer, String> consumer = new Consumer("processor-consumer", bootstrapServers, inputTopic,
   121→                 "processor-group", Optional.of(groupInstanceId), readCommitted, -1, null).createKafkaConsumer()) {
   122→            // called first and once to fence zombies and abort any pending transaction
   123→            producer.initTransactions();
   124→            consumer.subscribe(singleton(inputTopic), this);
   125→
   126→            Utils.printOut("Processing new records");
   127→            while (!closed && remainingRecords > 0) {
   128→                try {
   129→                    ConsumerRecords<Integer, String> records = consumer.poll(ofMillis(200));
   130→                    if (!records.isEmpty()) {
   131→                        // begin a new transaction session
   132→                        producer.beginTransaction();
   133→
   134→                        for (ConsumerRecord<Integer, String> record : records) {
   135→                            // process the record and send downstream
   136→                            ProducerRecord<Integer, String> newRecord =
   137→                                new ProducerRecord<>(outputTopic, record.key(), record.value() + "-ok");
   138→                            producer.send(newRecord);
   139→                        }
   140→
