   142→                        // note that this API is only available for broker >= 2.5
   143→                        producer.sendOffsetsToTransaction(getOffsetsToCommit(consumer), consumer.groupMetadata());
   144→
   145→                        // commit the transaction including offsets
   146→                        producer.commitTransaction();
   147→                        processedRecords += records.count();
   148→                        retries = 0;
   149→                    }
   150→                } catch (AuthorizationException | UnsupportedVersionException | ProducerFencedException
   151→                         | FencedInstanceIdException | OutOfOrderSequenceException | SerializationException e) {
   152→                    // we can't recover from these exceptions
   153→                    Utils.printErr(e.getMessage());
   154→                    shutdown();
   155→                } catch (OffsetOutOfRangeException | NoOffsetForPartitionException e) {
   156→                    // invalid or no offset found without auto.reset.policy
   157→                    Utils.printOut("Invalid or no offset found, using latest");
   158→                    consumer.seekToEnd(emptyList());
   159→                    consumer.commitSync();
   160→                    retries = 0;
   161→                } catch (KafkaException e) {
   162→                    // abort the transaction
   163→                    Utils.printOut("Aborting transaction: %s", e.getMessage());
   164→                    producer.abortTransaction();
   165→                    retries = maybeRetry(retries, consumer);
   166→                }
   167→
   168→                remainingRecords = getRemainingRecords(consumer);
   169→                if (remainingRecords != Long.MAX_VALUE) {
   170→                    Utils.printOut("Remaining records: %d", remainingRecords);
   171→                }
   172→            }
   173→        } catch (Throwable e) {
   174→            Utils.printErr("Unhandled exception");
   175→            e.printStackTrace();
   176→        }
   177→        Utils.printOut("Processed %d records", processedRecords);
   178→        shutdown();
   179→    }
   180→
   181→    @Override
   182→    public void onPartitionsRevoked(Collection<TopicPartition> partitions) {
   183→        Utils.printOut("Revoked partitions: %s", partitions);
   184→    }
   185→
   186→    @Override
   187→    public void onPartitionsAssigned(Collection<TopicPartition> partitions) {
   188→        Utils.printOut("Assigned partitions: %s", partitions);
   189→    }
   190→
   191→    @Override
   192→    public void onPartitionsLost(Collection<TopicPartition> partitions) {
   193→        Utils.printOut("Lost partitions: %s", partitions);
   194→    }
   195→
   196→    public void shutdown() {
   197→        if (!closed) {
   198→            closed = true;
   199→            latch.countDown();
   200→        }
   201→    }
   202→
   203→    private Map<TopicPartition, OffsetAndMetadata> getOffsetsToCommit(KafkaConsumer<Integer, String> consumer) {
   204→        Map<TopicPartition, OffsetAndMetadata> offsets = new HashMap<>();
   205→        for (TopicPartition topicPartition : consumer.assignment()) {
   206→            offsets.put(topicPartition, new OffsetAndMetadata(consumer.position(topicPartition), null));
   207→        }
   208→        return offsets;
   209→    }
   210→
   211→    private long getRemainingRecords(KafkaConsumer<Integer, String> consumer) {
   212→        final Map<TopicPartition, Long> fullEndOffsets = consumer.endOffsets(new ArrayList<>(consumer.assignment()));
   213→        // if we can't detect any end offset, that means we are still not able to fetch offsets
   214→        if (fullEndOffsets.isEmpty()) {
   215→            return Long.MAX_VALUE;
   216→        }
   217→        return consumer.assignment().stream().mapToLong(partition -> {
   218→            long currentPosition = consumer.position(partition);
   219→            if (fullEndOffsets.containsKey(partition)) {
   220→                return fullEndOffsets.get(partition) - currentPosition;
   221→            } else {
   222→                return 0;
   223→            }
   224→        }).sum();
   225→    }
   226→
   227→    /**
   228→     * When we get a generic {@code KafkaException} while processing records, we retry up to {@code MAX_RETRIES} times.
   229→     * If we exceed this threshold, we log an error and move on to the next batch of records.
   230→     * In a real world application you may want to to send these records to a dead letter topic (DLT) for further processing.
   231→     * 
   232→     * @param retries Current number of retries
   233→     * @param consumer Consumer instance
   234→     * @return Updated number of retries
   235→     */
   236→    private int maybeRetry(int retries, KafkaConsumer<Integer, String> consumer) {
   237→        if (retries < 0) {
   238→            Utils.printErr("The number of retries must be greater than zero");
   239→            shutdown();
   240→        }
   241→        
   242→        if (retries < MAX_RETRIES) {
   243→            // retry: reset fetch offset
   244→            // the consumer fetch position needs to be restored to the committed offset before the transaction started
   245→            Map<TopicPartition, OffsetAndMetadata> committed = consumer.committed(consumer.assignment());
   246→            consumer.assignment().forEach(tp -> {
   247→                OffsetAndMetadata offsetAndMetadata = committed.get(tp);
   248→                if (offsetAndMetadata != null) {
   249→                    consumer.seek(tp, offsetAndMetadata.offset());
   250→                } else {
   251→                    consumer.seekToBeginning(Collections.singleton(tp));
   252→                }
   253→            });
   254→            retries++;
   255→        } else {
   256→            // continue: skip records
   257→            // the consumer fetch position needs to be committed as if records were processed successfully
   258→            Utils.printErr("Skipping records after %d retries", MAX_RETRIES);
   259→            consumer.commitSync();
   260→            retries = 0;
   261→        }
   262→        return retries;
   263→    }
   264→
   265→    @Override
   266→    public void close() throws Exception {
   267→        if (producer != null) {
   268→            producer.close();
   269→        }
   270→
   271→        if (consumer != null) {
   272→            consumer.close();
   273→        }
   274→    }
   275→}
